input.oldString:
useEffect(() => {
  if (address && chains.length > 0) {
    loadSwapHistory()
    loadUserStreak()
    checkAirdrops()
  }
}, [address, chains])

input.newString:
useEffect(() => {
  if (address && chains.length > 0) {
    loadSwapHistory()
    loadUserStreak()
    checkAirdrops()

    // Check for new airdrops every 5 minutes
    const airdropInterval = setInterval(() => {
      checkAirdrops()
    }, 5 * 60 * 1000)

    return () => clearInterval(airdropInterval)
  }
}, [address, chains])
